        """Load a skill from disk."""
        with open(path) as f:
            content = f.read()

        # Parse YAML frontmatter if present
        parts = content.split('---\n', 2)
        if len(parts) == 3:
            import yaml
            metadata = yaml.safe_load(parts[1])
            body = parts[2]
        else:
            metadata = {}
            body = content

        return {
            'name': name,
            'metadata': metadata,
            'content': body,
            'path': path
        }

